24	  // ---- Components: runes/moonstones, with the 3-alike block discount ----
25	  it.todo("2 runes → base 50 G (then first-insurance and fee apply)");
26	  it.todo("3 runes → base 60 G (block applies)");
27	  it.todo("4 runes → base 100 G (no block — block requires exactly 3)");
28	  it.todo("7 runes → base 175 G (one block of 3 + 4 singles = 60 + 100)");
29	
30	  // ---- 'Alike' components clarifier ----
31	  it.todo("2 runes + 1 moonstone → base 75 G (no block: different types)");
32	  it.todo("3 runes + 3 moonstones → base 120 G (two separate blocks)");
33	
34	  // ---- Modifier scope on multi-item policies ----
35	  it.todo("policy with cursed sword + plain amulet → base 160 G + curse 50 G = 210 G before policy-wide modifiers and fee");
36	
37	  // ---- Modifier thresholds ----
38	  it.todo("customer with exactly 2 years with MHPCO → loyalty discount applies");
39	  it.todo("sword with exactly enchantment 5 → high-enchantment surcharge applies");
40	  it.todo("cursed sword with enchantment 5 → both curse and high-enchantment surcharges apply");
41	  it.todo("sword with enchantment 4 → no high-enchantment surcharge");
42	
43	  // ---- Integration examples (premium) ----
44	  it.todo("newcomer with cursed sword (steel, enchantment 3) → premium 165 G");
45	  it.todo("long-standing customer (3y), second contract, cursed sword (steel, enchantment 7) → premium 160 G");
46	
47	  // ---- Rounding ----
48	  it.todo("premium calculation yielding 197.5 G → final premium 198 G (rounded up in MHPCO's favor)");
49	
50	  // ---- Claim processing: standard reimbursement ----
