52	  it.todo("damage to rune (insurance value 250 G), damage 200 G → payout 100 G");
53	
54	  // ---- Enchantment threshold ----
55	  it.todo("steel sword, enchantment 9, damage 1000 G → payout 400 G (50% then 100 G deductible)");
56	
57	  // ---- Dragon material ----
58	  it.todo("dragon-material sword, enchantment 5, damage 800 G → payout 700 G (dragon full, then deductible)");
59	
60	  // ---- Enchantment threshold vs dragon material (both apply) ----
61	  it.todo("dragon-material sword, enchantment 8, damage 1000 G → payout 400 G (50% then deductible)");
62	  it.todo("dragon-material sword, enchantment 9, damage 1000 G → payout 400 G (50% rule wins, then deductible)");
63	
64	  // ---- Deductible per damage event ----
65	  it.todo("dragon attack damages sword (500) and amulet (300) → payout 600 G (deductible per damaged item)");
